		var GROUP_TREE;

function onClick()
{                   
  Ctrl('ocultarReporte').SetCValue(Ctrl('INFO_ocultarReporte').GetCValue());
	var MyITEM;
	var MyGROUP;
	var MyOBJ;


	MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
	MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());

	MyOBJ=(MyITEM?MyITEM:MyGROUP);
	if (MyOBJ)
	{   
		var subtag=MyOBJ.Tag.split("&")[0];
		var esttag=MyOBJ.Tag.split("&")[1];
		var myedit;
		var mydelete;
		var myadd;
		var myanule;
		var myfinalize;
		var myactive;
		var myasign; 
		var mytest;

		switch (subtag)
		{
			case "tareas-group":           
				//buscar el estato 1 nivel ARRIBA                            
				MyIDFind=Ctrl("TREE_ID").GetXValue().split("/");
				MyIDFind.length-=1;
				MyGRFind=GROUP_TREE.GetGroup(MyIDFind.join("/"));
				esttag=MyGRFind.Tag.split("&")[1];
			break;
		}


		if (esttag)
		{       
			switch(esttag)
			{
				case "I": //iniciada
					myedit  =true;
					mydelete=true;
					myadd   =true;
					myanule =false;
					myfinalize =false;
					myactive=true;
					myasign =false;  
					mytest = false;
				break;
				case "L": //Bloqueado
					myedit  =true;
					mydelete=true;
					myadd   =true;
					myanule =false;
					myfinalize =false;
					myactive=false;
					myasign =false; 
					mytest = false;
				break;
				case "P": //Pausada
					myedit  =true;
					myadd   =true;
					mydelete=false;  
					myanule =true;
					myfinalize =false; 
					myactive=true; 
					myasign =false; 
					mytest = false;
				break;
				case "T": //Trabajando
					//myedit  =false; EGG 20100219
					myedit  =true;
					mydelete=false;
					myadd   =true;
					myanule =true; 
					myfinalize =false;  //una tarea no puede finalizarse manualmente
					myactive=false;
					myasign =true; 
					mytest = true;
					if ((subtag=="proyecto-root") || (subtag=="proyecto-child"))
						{
						myedit=true;
						myfinalize =true; //un proyecto si puede finalizarse manualmente
						 }
				break;
        case "D": //Derivada a testing
					myedit  =true;
					mydelete=false;
					myadd   =true;
					myanule =true;
					myfinalize =true;
					myactive=false;
					myasign =true;  
					mytest = false;
				break;
				case "A": //Anulada
				case "F": //Finalizada
				default:
					myedit  =false;
					mydelete=false;
					myadd   =false;
					myanule =false;
					myfinalize =false;
					myactive=false;
					myasign =false; 
					mytest = false; 
				break;
			}

		} else
		{
			myedit  =false;
			mydelete=false;
			myadd   =false;
		}

		switch (subtag)
		{
		 	case "proyecto-root":
		 	case "proyecto-child":
				CtrlEnabled("SHOW"    ,true    );
				CtrlEnabled("ADD"     ,myadd   );
				CtrlEnabled("COPY"    ,false   );
				CtrlEnabled("EDIT"    ,myedit  );
				CtrlEnabled("DEL"     ,mydelete);				
				CtrlEnabled("TRELLO"  ,false	 );
				CtrlEnabled("SHOWTRELLO"  ,false	 );

				CtrlEnabled("WORK"    ,false);
				CtrlEnabled("ASIGN"   ,false);
				CtrlEnabled("PARATEST",false);
				CtrlEnabled("PAUSE"   ,false);
				CtrlEnabled("FINALIZE",myfinalize);
				CtrlEnabled("ANULE"   ,myanule);
		 	break;

			case "tareas-group":  
				CtrlEnabled("SHOW"    ,false);
				CtrlEnabled("ADD"     ,myadd);   
				CtrlEnabled("COPY"    ,false);
				CtrlEnabled("EDIT"    ,false);				
				CtrlEnabled("DEL"     ,false);
				CtrlEnabled("TRELLO"  ,false); 
				CtrlEnabled("SHOWTRELLO"  ,false	 );

				CtrlEnabled("WORK"    ,false);
				CtrlEnabled("ASIGN"   ,false); 
				CtrlEnabled("PARATEST",false);
				CtrlEnabled("PAUSE"   ,false);
				CtrlEnabled("FINALIZE",false);
				CtrlEnabled("ANULE"   ,false);
			break;

		 	case "tarea":
				CtrlEnabled("SHOW"    ,true    );
				CtrlEnabled("ADD"     ,myadd   );
				CtrlEnabled("COPY"    ,myadd   );
				CtrlEnabled("EDIT"    ,myedit  );
				CtrlEnabled("DEL"     ,mydelete);
				CtrlEnabled("TRELLO"  ,myadd	 );
				CtrlEnabled("SHOWTRELLO"  ,myadd	 );

				CtrlEnabled("WORK"    ,myactive);
				CtrlEnabled("ASIGN"   ,myasign ); 
				CtrlEnabled("PARATEST",mytest );
				CtrlEnabled("PAUSE"   ,myasign );
				CtrlEnabled("FINALIZE",myfinalize );
				CtrlEnabled("ANULE"   ,myanule );
		 	break;

			case "root":
			case "template":
				CtrlEnabled("SHOW"   ,false);
				CtrlEnabled("ADD"    ,true );
				CtrlEnabled("COPY"   ,false);
				CtrlEnabled("EDIT"   ,false);				
				CtrlEnabled("DEL"    ,false);
				CtrlEnabled("TRELLO" ,false); 
				CtrlEnabled("SHOWTRELLO"  ,false	 );

				CtrlEnabled("WORK"    ,false);
				CtrlEnabled("ASIGN"   ,false); 
				CtrlEnabled("PARATEST",false);
				CtrlEnabled("PAUSE"   ,false);
				CtrlEnabled("FINALIZE",false);
				CtrlEnabled("ANULE"   ,false);
			break;

			default:
				CtrlEnabled("SHOW"    ,false);
				CtrlEnabled("ADD"     ,false);
				CtrlEnabled("COPY"    ,false);
				CtrlEnabled("EDIT"    ,false);				
				CtrlEnabled("DEL"     ,false);
				CtrlEnabled("TRELLO" 	,false);
				CtrlEnabled("SHOWTRELLO"  ,false	 );

				CtrlEnabled("WORK"    ,false);
				CtrlEnabled("ASIGN"   ,false); 
				CtrlEnabled("PARATEST",false);
				CtrlEnabled("PAUSE"   ,false);
				CtrlEnabled("FINALIZE",false);
				CtrlEnabled("ANULE"   ,false);
			break;
		}             


		subtag=subtag.split("-")[0];
		strData=(Ctrl('INFO_ocultarReporte').TypedValue()?null:Ctrl("main").getResource("wiki:"+subtag));		


		if (strData) 
		{
			//Consulta                                 			
			MySQL=GetProxy().SQLService().GetXML(Ctrl("main").getResource("sql:"+subtag), '<DATA ID="'+MyOBJ.Id+'" />');

			strData=GenerateReport(strData,MySQL);
/*			strData=strData.split("#");
			for (t=1; t<strData.length; t+=2){


				if (strData[t].substr(0,6)=="CHILD:"){

				}else
				  strData[t]=MySQL.GetAttr(strData[t]);
			}	
			strData=strData.join("");*/
			Ctrl("INFO").SetXValue(strData);

			if(subtag=='tarea')
			{
			   MySQL=GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry_tarea_trello"), '<DATA ID="'+MyOBJ.Id+'" />');

			   if(MySQL.GetAttr("C_EXTERNO")=='0')
			   	CtrlEnabled("TRELLO" 	,true);
			   else
			   	CtrlEnabled("TRELLO" 	,false);

			   if(MySQL.GetAttr("D_ENLACE")=='0')
			   	CtrlEnabled("SHOWTRELLO" 	,false);
			   else
			   	CtrlEnabled("SHOWTRELLO" 	,true);
			}

		}

		else
		{
			Ctrl("INFO").SetXValue("**Sin información adicional.**");
		} 

	} 
	else
	{
		CtrlEnabled("SHOW"   ,false);
		CtrlEnabled("ADD"    ,false);
		CtrlEnabled("COPY"   ,false);
		CtrlEnabled("EDIT"   ,false);
		CtrlEnabled("DEL"    ,false);
		CtrlEnabled("TRELLO" ,false);
	}

}

function ObjtectGroupResult()
{  

 	this.processResult = function(xmlin)
	{                                   
		var objdata=new NomadXML(xmlin);
		var fullID=this.PrevID;
		if (objdata.GetAttr("id")!="") fullID=fullID+"/"+objdata.GetAttr("id")     
		var MyITEM =GROUP_TREE.GetItem(this.PrevID);
		var MyGROUP=GROUP_TREE.GetGroup(this.PrevID);

		var MyOBJ=(MyITEM?MyITEM:MyGROUP);

		if (MyOBJ)
		{        

			//Refrezco el arbol en caso de modificación del lugar del proyecto
			if(objdata.GetAttr("oi_proyecto_parent") != objdata.GetAttr("oi_proy_originalp"))
			{
			var nSQL = GetProxy().SQLService();
			var proy = nSQL.GetOBJ(Ctrl("main").getResource("qry:modProy"), '<DATA ID="'+objdata.GetAttr("oi_proyecto_parent")+'" />') 
			LoadChilds(GROUP_TREE, GROUP_TREE.GetGroup(proy.FullId));
			LoadChilds(GROUP_TREE, GROUP_TREE.GetGroup(this.PrevID)); 
			}
			else
			{ 
				//Refrezco el arbol en caso de modificación del lugar de la tarea
				if(objdata.GetAttr("oi_proyecto") != objdata.GetAttr("oi_proy_originalt"))
				{
				var nSQL = GetProxy().SQLService();
				var proy = nSQL.GetOBJ(Ctrl("main").getResource("qry:modTarea"), '<DATA ID="'+objdata.GetAttr("oi_proyecto")+'" />') 
				LoadChilds(GROUP_TREE, GROUP_TREE.GetGroup(proy.FullId)); 
				LoadChilds(GROUP_TREE, GROUP_TREE.GetGroup(this.PrevID));
				}
				else
				{ 
				LoadChilds(GROUP_TREE, GROUP_TREE.GetGroup(this.PrevID));
				}
			}

			GROUP_TREE.SetSelectedId(fullID);
		}               

		MyITEM =GROUP_TREE.GetItem(fullID);
		MyGROUP=GROUP_TREE.GetGroup(fullID);

		if (MyITEM) GROUP_TREE.ClickItem(fullID);
		if (MyGROUP) GROUP_TREE.ClickGroup(fullID);
	}
}     

function CALL_MODE(mode)
{                                      
	var MyITEM;
	var MyGROUP;
	var MyOBJ;

	MyITEM =GROUP_TREE.GetItem(Ctrl("TREE_ID").GetXValue());
	MyGROUP=GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue());

	MyOBJ=(MyITEM?MyITEM:MyGROUP);

	var MyRetVal=new ObjtectGroupResult();

	//Obtengo el ID Previo
	MyRetVal.PrevID=Ctrl("TREE_ID").GetXValue().split("/");
	if (MyRetVal.PrevID.length>1) MyRetVal.PrevID.length--;
	MyRetVal.PrevID=MyRetVal.PrevID.join("/");

	if (MyOBJ)
	{         
		var subtag=MyOBJ.Tag.split("&")[0];
		switch (subtag)
		{ 
			case "proyecto-root":
			case "proyecto-child":
				if (mode=="ADD") MyRetVal.PrevID=MyOBJ.FullId;
				openNewFlow("NucleusProject.Base.Project.Proyectos.MAIN.flow",mode,'<DATA id="'+MyOBJ.Id+'" />',MyRetVal,"L");
			break;    

			case "root":
			case "template":
				openNewFlow("NucleusProject.Base.Project.Proyectos.MAIN.flow",mode,'<DATA id="" />',MyRetVal,"L");
			break;

			case "tareas-group":                        
				MyRetVal.PrevID=MyOBJ.FullId;         
				openNewFlow("NucleusProject.Base.Project.Tareas.MAIN.flow",mode,'<DATA id="'+MyOBJ.Id.substr(2)+'" />',MyRetVal,"L");
			break;    

			case "tarea":
				if ((mode=="ADD") || (mode=="COPY"))
				{
					MyID=MyRetVal.PrevID.split("/");
					MyID=MyID[MyID.length-1];
					MyID=MyID.substr(2);
				} else
					MyID=MyOBJ.Id;
				////////////////////////////////////////////////////////////////////////////	
				openNewFlow("NucleusProject.Base.Project.Tareas.MAIN.flow",mode,'<DATA id="'+MyID+'" oi_tarea="'+MyOBJ.Id+'" />',MyRetVal,"L");
			break;       

			default:
				alert("Lo siento mucho...\r\nNo esta Implementado!")
			break;
		}
	}
}

function LoadChilds(objTree, objGroup)
{                        
	var subtag=objGroup.Tag.split("&")[0];     
	switch (subtag)
	{
		case "root":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-root"), ""));
		break;

		case "template":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-template"), ""));
		break;

		case "proyecto-root":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-child"), '<DATA ID="'+objGroup.Id+'" />'));
		break;

		case "proyecto-child":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-child"), '<DATA ID="'+objGroup.Id+'" />'));
		break;

		case "objetivo-group":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:project-objetivos"), '<DATA ID="'+objGroup.Id.substr(2)+'" />'));
		break;


		case "tareas-group":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:tarea"), '<DATA ID="'+objGroup.Id.substr(2)+'" />'));
		break;

		case "tarea-rec-group":
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:tarea-rec"), '<DATA ID="'+objGroup.Id.substr(2)+'" />'));
		break;

		case "traza-group":                                                                                    
			objTree.SetXML(objGroup.FullId, nSQL.Get(Ctrl("main").getResource("qry:tarea-traza"), '<DATA ID="'+objGroup.Id.substr(2)+'" />'));
		break;

		case "tarea-rec":
		break;

		case "tarea-traza":
		break;

		case "tarea-objetivo":
		break;

		default:
			alert("LoadChilds:"+objGroup.Tag+" "+objGroup.Id);
		break;
	}

}

