function SHOWTRELLO()
{  
	var MySQL;

	MySQL = GetProxy().SQLService().GetXML(Ctrl("main").getResource("qry_tarea_trello"), '<DATA ID="'+GROUP_TREE.GetGroup(Ctrl("TREE_ID").GetXValue()).Id+'" />');
	if(MySQL.GetAttr("D_ENLACE")=='0')
		alert("La Tarea no está vinculada con ninguna Tarjeta en Trello.");
	else
		{
		   window.open("https://trello.com/c/"+MySQL.GetAttr("D_ENLACE"));
		   return;
		}

}

