function OnLoad()
{              
Ctrl('INFO_ocultarReporte').SetCValue(Ctrl('ocultarReporte').GetCValue());
	np = new NomadProxy("", ut);
	nSQL = np.SQLService();

	GROUP_TREE=clsClientTree("CONT_PROJECT_TREE","TREE_ID","CLOCK.ico","folder-close.ico","folder.ico","item.ico",true,LoadChilds,null,onClick);	

	//Cargo los proyectos
	GROUP_TREE.SetXML(null, '<tree><group id="." label="Proyectos" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="root" /><group id="*" label="Plantillas" imgOpen="cabinet.ico" imgClose="cabinet-close.ico" tag="template" /></tree>');                                                         
	GROUP_TREE.ClickExpGroup(".");
	GROUP_TREE.ClickGroup(".");
}

function GenerateReport(strData, MySQL)
{
  var t;
  var micur;
  var parte;

  strData=strData.split("#");
	for (t=1; t<strData.length; t+=2)
	{
	 	 if (strData[t].substr(0,6).toUpperCase()=="CHILD:")
	 	 {
	 	   parte = strData[t].split(":");
	 	   strData[t] = "";
	 	   for (micur = MySQL.FindElement(parte[1]).FirstChild(); micur!=null;micur=micur.Next())
	 	   {
	 	     strData[t] += GenerateReport(Ctrl("main").getResource("wiki:"+parte[2]),micur)+"\r\n";
	 	   }
	   }else
	  		strData[t]=MySQL.GetAttr(strData[t]);
	}	
	return strData.join(""); 		
}

function ObjtectFind()
{             
 	this.processResult = function(xmlin)
	{        
		if (xmlin.indexOf("oi_tarea")>=0)
		{
	 		fullId=new NomadXML(nSQL.Get(Ctrl("main").getResource("qry:path"), xmlin));
	 		fullId=fullId.GetAttr("fullId");
	 		NomadTimeout("ChangeSelectID('"+fullId+"');",50,"Cargando el Arbol...");

 		}
	}
}

function ChangeSelectID(fullId)     
{
	Ctrl("TREE_ID").SetXValue(fullId);
	GROUP_TREE.SetSelectedId(fullId);
	onClick();
}


function FIND()
{
	var MyRetVal=new ObjtectFind();

	openNewFlow("NucleusProject.Base.Project.Tareas.TAREA.guia.flow","proy",'<DATA ESTADOS="FIT" />',MyRetVal,"L");
}
